import { IMessageComposer } from '@nitrots/nitro-renderer';

export class UseInventoryItemComposer implements IMessageComposer<any[]> {
    private _data: any[];

    constructor(itemId: number) {
        this._data = [itemId];
          console.log("Packet UseInventoryItemsComposer sent");
    }

    public getMessageArray(): any[] {
      
        return this._data;
    }

    public dispose(): void {
        return;
    }
}
